let raw = String($json.output ?? "");

// κρατάμε μόνο το κομμάτι μετά το <ΑΠΑΝΤΗΣΗ>
let text = raw.split("<ΑΠΑΝΤΗΣΗ>").pop().trim();

const contexts = [];

const steps = $json.intermediateSteps ?? [];

for (const step of steps) {

  let obs = step.observation;
  if (!obs) continue;

  try {

    // observation είναι string JSON array
    const arr = JSON.parse(obs);

    for (const item of arr) {

      if (!item.text) continue;

      // δεύτερο JSON.parse
      const inner = JSON.parse(item.text);

      if (inner.pageContent) {

        contexts.push(
          String(inner.pageContent).slice(0,1200)
        );

      }

    }

  } catch(e) {}

}

return [{
  json:{
    text,
    contexts
  }
}];

